const NORMALIZA_ENTRADA_CHATWOOT_VERSION = "v5_labels_bruna_sem_direct_handoff";

const firstItem = $("Webhook").first()?.json || {};
const envelope = Array.isArray(firstItem) ? (firstItem[0] || {}) : firstItem;
const body = envelope.body && typeof envelope.body === "object" ? envelope.body : envelope;
const headers = envelope.headers || {};

const BRUNA_LABELS = new Set([
  "01-bruna-atendimento",
]);

const HUMAN_LABELS = new Set([
  "01-humano-assumiu",
]);

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function onlyDigits(value) {
  return clean(value).replace(/\D/g, "");
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }
  return "";
}

function normalizeLabel(label) {
  return clean(label).toLowerCase();
}

function normalizeLabels(value) {
  if (Array.isArray(value)) {
    return value
      .map(label => clean(label))
      .filter(Boolean);
  }

  if (value && typeof value === "object") {
    if (Array.isArray(value.payload)) return normalizeLabels(value.payload);
    if (Array.isArray(value.labels)) return normalizeLabels(value.labels);
  }

  if (typeof value === "string") {
    return value
      .split(",")
      .map(label => clean(label))
      .filter(Boolean);
  }

  return [];
}

function getLabelsFromListaEtiquetas() {
  try {
    const nodeItem = $("Lista Etiquetas").first()?.json || {};
    return normalizeLabels(nodeItem.payload || nodeItem.labels || nodeItem);
  } catch (error) {
    return [];
  }
}

function nowIso() {
  return new Date().toISOString();
}

const labels = getLabelsFromListaEtiquetas();
const labelsLower = labels.map(normalizeLabel);

const hasBrunaLabel = labelsLower.some(label => BRUNA_LABELS.has(label));
const hasHumanLabel = labelsLower.some(label => HUMAN_LABELS.has(label));
const shouldProcessByLabels = hasBrunaLabel && !hasHumanLabel;

function ignored(reason, extra = {}) {
  return [{
    json: {
      action: "ignore",
      event: clean(body.event),
      ignore: {
        reason,
        ...extra,
      },
      routing: {
        should_process: false,
        should_reply: false,
        should_handoff: false,
        route_action: "ignore",
        channel: "chatwoot_whatsapp",
      },
      conversation: {
        labels,
      },
      chatwoot: {
        account_id: body.account?.id || body.conversation?.account_id || null,
        inbox_id: body.inbox?.id || body.conversation?.inbox_id || null,
        conversation_id: body.conversation?.id || null,
        contact_id: body.sender?.id || body.conversation?.meta?.sender?.id || null,
        message_id: body.id || null,
        delivery_id: headers["x-chatwoot-delivery"] || "",
      },
      debug: {
        normaliza_entrada_chatwoot_version: NORMALIZA_ENTRADA_CHATWOOT_VERSION,
        labels,
        labels_source: "Lista Etiquetas",
        has_bruna_label: hasBrunaLabel,
        has_human_label: hasHumanLabel,
        should_process_by_labels: shouldProcessByLabels,
        received_body: body,
      },
    },
  }];
}

const conversation = body.conversation || {};
const messages = Array.isArray(conversation.messages) ? conversation.messages : [];
const primaryMessage = messages.find((message) => String(message.id) === String(body.id)) || messages[0] || {};
const sender = body.sender || conversation.meta?.sender || primaryMessage.sender || {};

const event = clean(body.event);
const messageType = clean(body.message_type);
const numericMessageType = primaryMessage.message_type;
const senderType = clean(primaryMessage.sender_type || sender.type);
const isIncoming = messageType === "incoming" || numericMessageType === 0 || senderType.toLowerCase() === "contact";
const isPrivate = body.private === true || primaryMessage.private === true;
const canReply = conversation.can_reply !== false;
const rawContentType = clean(body.content_type || primaryMessage.content_type || "text");
const attachments = Array.isArray(body.attachments)
  ? body.attachments
  : (Array.isArray(primaryMessage.attachments) ? primaryMessage.attachments : []);
const hasAttachment = attachments.length > 0;
const firstAttachment = attachments[0] || {};
const dataUrl = firstFilled(
  firstAttachment.data_url,
  firstAttachment.download_url,
  firstAttachment.file_url,
  firstAttachment.url
) || null;
const content = clean(
  firstFilled(body.content, body.messages?.[0]?.content, primaryMessage.processed_message_content, primaryMessage.content)
)
  .replace(/\[object Object\]/gi, "")
  .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
  .replace(/\uFFFD/g, " ")
  .replace(/\s+/g, " ")
  .trim();
const hasText = content.length > 0;
const mediaType = hasAttachment
  ? clean(firstAttachment.file_type || firstAttachment.type || firstAttachment.content_type || "attachment").toLowerCase()
  : "none";
const messageModality = hasAttachment && hasText
  ? `${mediaType}_with_text`
  : hasAttachment
    ? `${mediaType}_only`
    : hasText
      ? "text_only"
      : "unknown";
const contentType = messageModality;

if (event && event !== "message_created") {
  return ignored("evento_nao_message_created");
}

if (!isIncoming) {
  return ignored("mensagem_nao_incoming", { message_type: messageType, sender_type: senderType });
}

if (isPrivate) {
  return ignored("mensagem_privada");
}

if (!canReply) {
  return ignored("conversa_sem_permissao_de_resposta");
}

if (hasHumanLabel) {
  return ignored("label_humano_assumiu", { labels });
}

if (!hasBrunaLabel) {
  return ignored("sem_label_bruna", { labels });
}

if (!shouldProcessByLabels) {
  return ignored("labels_nao_permitem_bruna", { labels });
}

if (!content && !hasAttachment) {
  return ignored("mensagem_sem_texto_e_sem_anexo");
}

const accountId = body.account?.id || conversation.account_id || null;
const inboxId = body.inbox?.id || conversation.inbox_id || null;
const conversationId = conversation.id || primaryMessage.conversation_id || null;
const contactId = sender.id || primaryMessage.sender_id || conversation.meta?.sender?.id || null;
const phone = onlyDigits(firstFilled(sender.phone_number, sender.identifier, primaryMessage.sender?.phone_number));
const sessionKey = phone || contactId || conversationId || body.id || Date.now();
const sessionId = `chatwoot-a${accountId || "x"}-${sessionKey}`;
const contactName = firstFilled(sender.name, conversation.meta?.sender?.name);
const attachmentSummary = hasAttachment
  ? attachments.map((attachment, index) => {
      const kind = firstFilled(attachment.file_type, attachment.content_type, attachment.message_type, attachment.data_url, "anexo");
      const url = firstFilled(attachment.data_url, attachment.download_url, attachment.file_url, attachment.url);
      return `Anexo ${index + 1}: ${kind}${url ? ` - ${url}` : ""}`;
    }).join("\n")
  : "";
const shouldAskForText = hasAttachment && !content;
const safeContent = content
  ? [content, attachmentSummary ? `\nContexto de mídia recebida:\n${attachmentSummary}` : ""].join("").trim()
  : `[Mensagem com anexo sem legenda. message_modality=${messageModality || "unknown"}]`;

return [{
  json: {
    action: "sendMessage",
    sessionId,
    chatInput: safeContent,
    lead: {
      id: contactId || sessionKey,
      name: contactName,
      phone,
      origem: firstFilled(sender.custom_attributes?.origem, ""),
      anuncio: firstFilled(sender.custom_attributes?.anuncio, ""),
      link_rastreavel: firstFilled(sender.custom_attributes?.link_rastreavel, ""),
    },
    message: {
      role: "lead",
      content,
      content_for_ai: safeContent,
      has_text: hasText,
      has_attachment: hasAttachment,
      content_type: contentType,
      message_modality: messageModality,
      raw_content_type: rawContentType,
      data_url: dataUrl,
      media_type: mediaType,
      created_at: firstFilled(body.created_at, primaryMessage.updated_at, nowIso()),
    },
    conversation: {
      is_test: false,
      memory_enabled: true,
      history_source: "chatwoot_subworkflow",
      labels,
      has_bruna_label: hasBrunaLabel,
      has_human_label: hasHumanLabel,
      status: clean(conversation.status),
      unread_count: conversation.unread_count || 0,
      assignee_id: conversation.assignee_id || null,
      team_id: conversation.meta?.team?.id || null,
      team_name: conversation.meta?.team?.name || "",
    },
    chatwoot: {
      account_id: accountId,
      inbox_id: inboxId,
      conversation_id: conversationId,
      contact_id: contactId,
      message_id: body.id || primaryMessage.id || null,
      source_id: firstFilled(body.source_id, primaryMessage.source_id),
      delivery_id: headers["x-chatwoot-delivery"] || "",
      webhook_url: envelope.webhookUrl || "",
      raw_event: event || "message_created",
    },
    routing: {
      should_process: shouldProcessByLabels,
      should_reply: shouldProcessByLabels,
      should_handoff: false,
      route_action: "agent",
      direct_handoff_motivo: "",
      channel: "chatwoot_whatsapp",
    },
    agent: {
      memory_session_id: sessionId,
      ai_input: [
        "MENSAGEM ATUAL DO LEAD:",
        safeContent,
        "",
        hasAttachment ? "OBSERVAÇÃO: o lead enviou mídia/anexo. Se houver legenda, use a legenda como contexto. Se não houver texto suficiente, peça uma descrição objetiva em vez de encaminhar automaticamente para humano." : "",
        "",
        "DADOS TÉCNICOS DO CONTATO:",
        `Telefone: ${phone || "não informado"}`,
        "",
        "OBSERVAÇÃO IMPORTANTE:",
        "Não use o nome de perfil do WhatsApp/Chatwoot como nome confirmado da pessoa.",
        "O nome da pessoa só deve ser considerado confirmado se aparecer claramente no histórico ou na mensagem atual.",
        "",
        "CONTEXTO CHATWOOT:",
        `Conta: ${accountId || ""}`,
        `Inbox: ${inboxId || ""}`,
        `Conversa: ${conversationId || ""}`,
        `Labels: ${labels.join(", ") || "sem labels"}`,
        "",
        "INSTRUÇÃO:",
        "Responda como Bruna, atendente virtual da AuAu Creche Canina, seguindo o prompt do agente.",
        "Se precisar encaminhar para humano, retorne handoff_humano=true com um motivo permitido.",
      ].join("\n"),
    },
    debug: {
      normaliza_entrada_chatwoot_version: NORMALIZA_ENTRADA_CHATWOOT_VERSION,
      original_message_type: messageType,
      numeric_message_type: numericMessageType,
      sender_type: senderType,
      has_attachment: hasAttachment,
      content_type: contentType,
      labels,
      labels_source: "Lista Etiquetas",
      has_bruna_label: hasBrunaLabel,
      has_human_label: hasHumanLabel,
      should_process_by_labels: shouldProcessByLabels,
      direct_handoff: false,
      should_ask_for_text: shouldAskForText,
      attachment_summary: attachmentSummary,
      data_url: dataUrl,
    },
  },
}];

