JSON.stringify((() => {
  function normalizeLabels(value) {
    return (Array.isArray(value) ? value : [value])
      .flat(Infinity)
      .map(label => {
        if (typeof label === 'string') return label;

        if (label && typeof label === 'object') {
          return label.title || label.name || label.value || label.label || '';
        }

        return '';
      })
      .map(label => String(label).trim())
      .filter(Boolean);
  }

  const labelsAtuais = normalizeLabels(
    $('Webhook').first().json.body?.conversation?.labels || []
  );

  const labelsNovas = normalizeLabels(
    $json.labels_new || []
  );

  const labels = [...new Set([
    ...labelsAtuais,
    ...labelsNovas,
  ])];

  return {
    labels,
  };
})())
}}

