const payload = $json;

const sessionId =
  payload.sessionId ??
  payload.agent?.memory_session_id ??
  payload.chatwoot?.conversation_id?.toString() ??
  payload.conversation_id?.toString() ??
  payload.phone ??
  payload.lead?.phone;

const messageId =
  payload.chatwoot?.message_id?.toString() ??
  payload.message_id?.toString() ??
  payload.id?.toString() ??
  payload.chatwoot?.delivery_id ??
  payload.delivery_id;

if (!sessionId) {
  throw new Error('Não foi possível identificar o session_id');
}

if (!messageId) {
  throw new Error('Não foi possível identificar o message_id');
}

return [{
  json: {
    session_id: String(sessionId),
    message_id: String(messageId),
    payload
  }
}];
